-- Cleanup existing tables
DROP TABLE IF EXISTS PROTEIN_GO_ANNOTATIONS;
DROP TABLE IF EXISTS GO_TERMS;
DROP TABLE IF EXISTS PROTEINS;
DROP TABLE IF EXISTS ORGANISMS;

-- Create Schema
CREATE TABLE ORGANISMS (
    taxon_id VARCHAR(20) PRIMARY KEY,
    organism_name VARCHAR(100) NOT NULL
);

CREATE TABLE PROTEINS (
    protein_id VARCHAR(15) PRIMARY KEY,
    taxon_id VARCHAR(20) NOT NULL,
    symbol VARCHAR(20),
    name VARCHAR(150),
    type VARCHAR(20),
    FOREIGN KEY (taxon_id) REFERENCES ORGANISMS(taxon_id)
);

CREATE TABLE GO_TERMS (
    go_id CHAR(10) PRIMARY KEY,
    aspect CHAR(1) NOT NULL
);

CREATE TABLE PROTEIN_GO_ANNOTATIONS (
    annotation_id INT AUTO_INCREMENT PRIMARY KEY,
    protein_id VARCHAR(15) NOT NULL,
    go_id CHAR(10) NOT NULL,
    evidence_code CHAR(3),
    reference VARCHAR(30),
    assigned_by VARCHAR(30),
    date DATE,
    FOREIGN KEY (protein_id) REFERENCES PROTEINS(protein_id),
    FOREIGN KEY (go_id) REFERENCES GO_TERMS(go_id)
);

